#!/bin/bash
# MongoDB Atlas CLI Management
set -euo pipefail

echo "=== Atlas Projects ==="
atlas projects list --output json | mongosh --nodb --quiet --eval "
const projects = JSON.parse(cat());
projects.results.forEach(p => {
  print(p.id + ': ' + p.name + ' (org: ' + p.orgId + ')');
});
" 2>/dev/null || atlas projects list

echo ""
echo "=== Clusters ==="
atlas clusters list --output json | mongosh --nodb --quiet --eval "
const clusters = JSON.parse(cat());
clusters.results.forEach(c => {
  print(c.name + ': ' + c.stateName + ' | ' + c.providerSettings.providerName +
    ' ' + c.providerSettings.regionName + ' | tier: ' + c.providerSettings.instanceSizeName);
});
" 2>/dev/null || atlas clusters list

echo ""
echo "=== Database Users ==="
atlas dbusers list

echo ""
echo "=== IP Access List ==="
atlas accessLists list

echo ""
echo "=== Connection Strings ==="
for CLUSTER in $(atlas clusters list --output json 2>/dev/null | mongosh --nodb --quiet --eval "JSON.parse(cat()).results.forEach(c => print(c.name))" 2>/dev/null || atlas clusters list --output go-template='{{range .results}}{{.name}}{{"
"}}{{end}}'); do
  echo "--- $CLUSTER ---"
  atlas clusters connectionStrings describe "$CLUSTER" 2>/dev/null || echo "  (unable to fetch)"
done
